// ── availability-engine / day-view ───────────────────────────────────────────
// Input: POST body with customer_id, date (YYYY-MM-DD), duration_minutes, timezone
// tenant_id comes from x-tenant-id header (injected by the API Gateway from JWT).
// Algorithm:
//   1. Load working hours, busy periods, and day exceptions in parallel
//   2. Resolve effective working windows for the requested date (exceptions override)
//   3. Project busy windows onto the day, expand with buffers
//   4. Slice free slots from working windows minus busy windows
//   5. Return {
//        success: true,
//        data: {
//          date,
//          is_closed,
//          working_windows: [{ start, end }],
//          busy_windows:    [{ start, end, source }],
//          free_slots:      [{ start, end }],
//        }
//      }

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

function supabaseRpc(fnName, params) {
  return $helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/rpc/${fnName}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation',
    },
    body: JSON.stringify(params),
  });
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function localTimeToMs(dateStr, timeStr, tz) {
  const isoLike = `${dateStr}T${timeStr}:00`;
  const naiveMs = new Date(isoLike + 'Z').getTime();
  const fmt = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hour12: false,
  });
  const parts = fmt.formatToParts(new Date(naiveMs));
  const p = {};
  for (const { type, value } of parts) p[type] = value;
  const localMs = Date.UTC(
    parseInt(p.year), parseInt(p.month) - 1, parseInt(p.day),
    parseInt(p.hour === '24' ? '0' : p.hour), parseInt(p.minute), parseInt(p.second)
  );
  return naiveMs - (localMs - naiveMs);
}

function getDow(dateStr, tz) {
  // Parse date at noon to avoid DST edge cases
  const ms = localTimeToMs(dateStr, '12:00', tz);
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz, weekday: 'short',
  }).formatToParts(new Date(ms));
  const day = parts.find(p => p.type === 'weekday').value;
  return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].indexOf(day);
}

function overlapsAny(slotStartMs, slotEndMs, busyWindows) {
  for (const b of busyWindows) {
    if (slotStartMs < b.endMs && slotEndMs > b.startMs) return true;
  }
  return false;
}

// ── Main ──────────────────────────────────────────────────────────────────────

const item       = $input.first();
const headers    = item.json.headers || {};
const body       = item.json.body   || {};
const tenantId   = headers['x-tenant-id'];

const { customer_id, date, timezone = 'Europe/Berlin' } = body;
const durationMin = Number(body.duration_minutes) || 30;
const durationMs  = durationMin * 60 * 1000;

const dayStartMs = localTimeToMs(date, '00:00', timezone);
const dayEndMs   = localTimeToMs(date, '23:59', timezone) + 60000; // exclusive end
const dow        = getDow(date, timezone);

// Fetch all needed data in parallel
let workingHours, busyPeriods, exceptions;
try {
  [workingHours, busyPeriods, exceptions] = await Promise.all([
    supabaseRpc('ae_get_working_hours', {
      p_tenant_id: tenantId, p_customer_id: customer_id,
    }),
    supabaseRpc('ae_get_busy_periods', {
      p_tenant_id: tenantId, p_customer_id: customer_id,
      p_from: new Date(dayStartMs).toISOString(),
      p_to:   new Date(dayEndMs).toISOString(),
    }),
    supabaseRpc('ae_get_day_exceptions', {
      p_tenant_id:   tenantId, p_customer_id: customer_id,
      p_from_date:   date,
      p_to_date:     date,
    }),
  ]);
} catch (err) {
  return [{ json: { success: false, error: { code: 'DB_ERROR', message: err.message } } }];
}

const dayExceptions = exceptions || [];
const isClosed = dayExceptions.some(ex => ex.is_closed);

if (isClosed) {
  return [{ json: {
    success: true,
    data: {
      date,
      is_closed: true,
      working_windows: [],
      busy_windows:    [],
      free_slots:      [],
    },
  } }];
}

// Effective working windows for this day-of-week
const dayWhWindows = (workingHours || []).filter(wh => wh.day_of_week === dow);

if (dayWhWindows.length === 0) {
  return [{ json: {
    success: true,
    data: {
      date,
      is_closed: false,
      working_windows: [],
      busy_windows:    [],
      free_slots:      [],
    },
  } }];
}

// Build working_windows output (in ISO timestamps)
const workingWindows = dayWhWindows.map(wh => ({
  start: new Date(localTimeToMs(date, wh.start_time_text, timezone)).toISOString(),
  end:   new Date(localTimeToMs(date, wh.end_time_text,   timezone)).toISOString(),
}));

// Partial exceptions (time-of-day blocks)
const partialExceptions = dayExceptions
  .filter(ex => !ex.is_closed && ex.start_time_txt && ex.end_time_txt)
  .map(ex => ({
    startMs: localTimeToMs(date, ex.start_time_txt, timezone),
    endMs:   localTimeToMs(date, ex.end_time_txt,   timezone),
  }));

// busy_windows from appointments + blocks (raw, for output)
const rawBusyWindows = (busyPeriods || []).map(b => ({
  start:  b.start_at,
  end:    b.end_at,
  source: b.source,
  startMs: new Date(b.start_at).getTime(),
  endMs:   new Date(b.end_at).getTime(),
}));

// Add partial exceptions to busy_windows output
const allBusyForOutput = [
  ...rawBusyWindows.map(b => ({ start: b.start, end: b.end, source: b.source })),
  ...partialExceptions.map(pe => ({
    start:  new Date(pe.startMs).toISOString(),
    end:    new Date(pe.endMs).toISOString(),
    source: 'exception',
  })),
];

// Compute free slots across all working windows
const freeSlots = [];

for (const wh of dayWhWindows) {
  const bufBefore = (wh.buffer_before_min || 0) * 60000;
  const bufAfter  = (wh.buffer_after_min  || 0) * 60000;

  const winStart = localTimeToMs(date, wh.start_time_text, timezone);
  const winEnd   = localTimeToMs(date, wh.end_time_text,   timezone);

  // Busy windows expanded with buffers
  const buffered = [
    ...rawBusyWindows.map(b => ({
      startMs: b.startMs - bufBefore,
      endMs:   b.endMs   + bufAfter,
    })),
    ...partialExceptions,
  ];

  let t = winStart;
  while (t + durationMs <= winEnd) {
    if (!overlapsAny(t, t + durationMs, buffered)) {
      freeSlots.push({
        start: new Date(t).toISOString(),
        end:   new Date(t + durationMs).toISOString(),
      });
    }
    t += durationMs;
  }
}

return [{ json: {
  success: true,
  data: {
    date,
    is_closed:       false,
    working_windows: workingWindows,
    busy_windows:    allBusyForOutput,
    free_slots:      freeSlots,
  },
} }];
